722:       aChain, piTarget->GetTargetForEventTargetChain(), aChild);
723:   if (!etci->IsValid()) {
724:     EventTargetChainItem::DestroyLast(aChain, etci);
725:     return nullptr;
726:   }
727:   return etci;
