  }\n7207:       const RefPtr\u003cTextComposition\u003e textComposition =\n7208:           IMEStateManager::GetTextCompositionFor(focusedPresContext);\n7209:       if (!textComposition) {\n7210:         break;\n7211:       }\n7212:       // If there is a composition and it's managed by an editor, let's notify\n7213:       // the editor of mouse button event.  The editor commits the composition\n7214:       // unless IME consumes the event.\n7215:       if (RefPtr\u003cEditorBase\u003e editorBase = textComposition-\u003eGetEditorBase()) {\n7216:         MOZ_ASSERT(aGUIEvent-\u003eAsMouseEvent());\n7217:         editorBase-\u003eWillHandleMouseButtonEvent(*aGUIEvent-\u003eAsMouseEvent());\n7218:       }\n7219:       // Otherwise, we should commit the orphan composition instead.\n7220:       else if (nsCOMPtr\u003cnsIWidget\u003e widget = textComposition-\u003eGetWidget()) {\n7221:         textComposition-\u003eRequestToCommit(widget, false);\n7222:       }\n7223:       if (!CanHandleUserInputEvents(aGUIEvent)) {\n7224:         return NS_OK;\n7225:       }\n7226:       // Before bug 1945988, we dispatched the mouse button event without\n7227:       // committing composition and the editor will commit composition.\n7228:       // However, for compatibility with the other browsers, we started\n7229:       // committing composition before dispatching the mouse event.  To keep\n7230:       // the traditional behavior, we should compute aFrameForPresShell if it's\n7231:       // reframed by dispatching the composition events (and input events)\n7232:       // above.  Otherwise, we stop dispatching the mouse button events newly in\n7233:       // such case.\n7234:       if (MOZ_UNLIKELY(!weakFrameForPresShell.IsAlive())) {\n7235:         FlushPendingNotifications(FlushType::Layout);\n7236:         if (MOZ_UNLIKELY(IsDestroying())) {\n7237:           return NS_OK;\n7238:         }\n7239:         nsIFrame* const newFrameForPresShell = GetRootFrame();\n7240:         if (MOZ_UN