7130: nsresult PresShell::HandleEvent(nsIFrame* aFrameForPresShell,
7131:                                 WidgetGUIEvent* aGUIEvent,
7132:                                 bool aDontRetargetEvents,
7133:                                 nsEventStatus* aEventStatus) {
7134:   MOZ_ASSERT(aGUIEvent);
7135: 
7136:   RecordModifiers(aGUIEvent);
7137: 
7138:   AutoWeakFrame weakFrameForPresShell(aFrameForPresShell);
7139: 
7140:   // Running tests must not expect that some mouse boundary events are fired
7141:   // when something occurs in the parent process, e.g., when a popup is
7142:   // opened/closed at the last mouse cursor position in the parent process (the
7143:   // position may be different from the position which stored in this process).
7144:   // Therefore, let's ignore synthesized mouse events coming form another
7145:   // process if and only if they are not caused by the API.
7146:   if (aGUIEvent->CameFromAnotherProcess() && XRE_IsContentProcess() &&
7147:       !aGUIEvent->mFlags.mIsSynthesizedForTests) {
7148:     const PointerInfo* const lastMouseInfo =
7149:         PointerEventHandler::GetLastMouseInfo();
7150:     if (lastMouseInfo && lastMouseInfo->mIsSynthesizedForTests) {
7151:       switch (aGUIEvent->mMessage) {
7152:         // Synthesized eMouseMove will case mouse boundary events like
7153:         // mouseover, mouseout, and :hover state is changed at dispatching the
7154:         // events.
7155:         case eMouseMove:
7156:         // eMouseExitFromWidget comes from the parent process if the cursor
7157:         // crosses a puppet widget boundary.  Then, the event will be handled as
7158:         // a synthesized eMouseMove in this process and may cause unexpected
7159:         // `mouseout` and `mouseleave`.
7160:         case eMouseExitFromWidget:
7161:         // eMouseEnterIntoWidget causes updating the hover state under the event
7162:         // position which may be different from the last cursor position
7163:         // synthesized in this process.
7164:         case eMouseEnterIntoWidget:
7165:           if (!aGUIEvent->AsMouseEvent()->IsReal()) {
7166:             return NS_OK;
7167:           }
7168:           break;
7169:         default:
7170:           break;
7171:       }
7172:     }
7173:   }
7174: 
7175:   // Here we are granting some delays to ensure that user input events are
7176:   // created while the page content may not be visible to the user are not
7177:   // processed.
7178:   // The main purpose of this is to avoid user inputs are handled in the
7179:   // new document where as the user inputs were originally targeting some
7180:   // content in the old document.
7181:   if (!CanHandleUserInputEvents(aGUIEvent)) {
7182:     return NS_OK;
7183:   }
7184: 
7185:   // If there is a composition and we got a pointing device events which may not
7186:   // impossible to continue the composition, we should notify the editor of the
7187:   // event before dispatching it.  Then, composition will be commited before
7188:   // the editor loses focus.  This behavior is compatible with Chrome.
7189:   // FIXME: Perhaps, we should do same thing before dispatching touch events.
7190:   switch (aGUIEvent->mMessage) {
7191:     case eMouseDown:
7192:     case eMouseUp: {
7193:       nsPIDOMWindowOuter* const focusedWindow =
7194:           nsFocusManager::GetFocusedWindowStatic();
7195:       if (!focusedWindow) {
7196:         break;
7197:       }
7198:       Document* const focusedDocument = focusedWindow->GetExtantDoc();
7199:       if (!focusedDocument) {
7200:         break;
7201:       }
7202:       nsPresContext* const focusedPresContext =
7203:           focusedDocument->GetPresContext();
7204:       if (!focusedPresContext) {
7205:         break;
7206:       }
7207:       const RefPtr<TextComposition> textComposition =
7208:           IMEStateManager::GetTextCompositionFor(focusedPresContext);
7209:       if (!textComposition) {
7210:         break;
7211:       }
7212:       // If there is a composition and it's managed by an editor, let's notify
7213:       // the editor of mouse button event.  The editor commits the composition
7214:       // unless IME consumes the event.
7215:       if (RefPtr<EditorBase> editorBase = textComposition->GetEditorBase()) {
7216:         MOZ_ASSERT(aGUIEvent->AsMouseEvent());
7217:         editorBase->WillHandleMouseButtonEvent(*aGUIEvent->AsMouseEvent());
7218:       }
7219:       // Otherwise, we should commit the orphan composition instead.
7220:       else if (nsCOMPtr<nsIWidget> widget = textComposition->GetWidget()) {
7221:         textComposition->RequestToCommit(widget, false);
7222:       }
7223:       if (!CanHandleUserInputEvents(aGUIEvent)) {
7224:         return NS_OK;
7225:       }
7226:       // Before bug 1945988, we dispatched the mouse button event without
7227:       // committing composition and the editor will commit composition.
7228:       // However, for compatibility with the other browsers, we started
7229:       // committing composition before dispatching the mouse event.  To keep
7230:       // the traditional behavior, we should compute aFrameForPresShell if it's
7231:       // reframed by dispatching the composition events (and input events)
7232:       // above.  Otherwise, we stop dispatching the mouse button events newly in
7233:       // such case.
7234:       if (MOZ_UNLIKELY(!weakFrameForPresShell.IsAlive())) {
7235:         FlushPendingNotifications(FlushType::Layout);
7236:         if (MOZ_UNLIKELY(IsDestroying())) {
7237:           return NS_OK;
7238:         }
7239:         nsIFrame* const newFrameForPresShell = GetRootFrame();
7240:         if (MOZ_UNLIKELY(!newFrameForPresShell)) {
7241:           return NS_OK;
7242:         }
7243:         weakFrameForPresShell = newFrameForPresShell;
7244:       }
7245:       break;
7246:     }
7247:     default:
7248:       break;
7249:   }
