9099: nsresult PresShell::EventHandler::DispatchEvent(
9100:     EventStateManager* aEventStateManager, WidgetEvent* aEvent,
9101:     bool aTouchIsNew, nsEventStatus* aEventStatus,
9102:     nsIContent* aOverrideClickTarget) {
9103:   MOZ_ASSERT(aEventStateManager);
9104:   MOZ_ASSERT(aEvent);
9105:   MOZ_ASSERT(aEventStatus);
9106: 
9107:   // 1. Give event to event manager for pre event state changes and
9108:   //    generation of synthetic events.
9109:   {  // Scope for presContext
9110:     RefPtr<nsPresContext> presContext = GetPresContext();
9111:     nsCOMPtr<nsIContent> eventContent =
9112:         mPresShell->mCurrentEventTarget.mContent;
9113:     nsresult rv = aEventStateManager->PreHandleEvent(
9114:         presContext, aEvent, mPresShell->mCurrentEventTarget.mFrame,
9115:         eventContent, aEventStatus, aOverrideClickTarget);
9116:     if (NS_FAILED(rv)) {
9117:       return rv;
9118:     }
9119:     // Let's retarget eMouseMove target if the preceding mouse boundary events
9120:     // caused removing the target from the tree and EventStateManager knows that
9121:     // the deepest connected mouseenter target which was an ancestor of the
9122:     // removed target.  This matches with Chrome Canary with enabling the
9123:     // new mouse/pointer boundary event feature.  However, they stop dispatching
9124:     // "pointermove" in the same case.  Therefore, for now, we should do this
9125:     // only for eMouseMove.
9126:     if (eventContent && aEvent->mMessage == eMouseMove &&
9127:         (!eventContent->IsInComposedDoc() ||
9128:          eventContent->OwnerDoc() != mPresShell->GetDocument())) {
9129:       const OverOutElementsWrapper* const boundaryEventTargets =
9130:           aEventStateManager->GetExtantMouseBoundaryEventTarget();
9131:       const nsIContent* outEventTarget =
9132:           boundaryEventTargets ? boundaryEventTargets->GetOutEventTarget()
9133:                                : nullptr;
9134:       nsIContent* const deepestLeaveEventTarget =
9135:           boundaryEventTargets
9136:               ? boundaryEventTargets->GetDeepestLeaveEventTarget()
9137:               : nullptr;
9138:       // If the last "over" target (next "out" target) is there, it means that
9139:       // it was temporarily removed.  In such case, EventStateManager treats
9140:       // it as never disconnected.  Therefore, we need to do nothing here.
9141:       // Additionally, if there is no last deepest "enter" event target, we
9142:       // lost the target.  Therefore, we should keep the traditional behavior,
9143:       // to dispatch it on the Document node.
9144:       if (!outEventTarget && deepestLeaveEventTarget) {
9145:         nsIFrame* const frame =
9146:             deepestLeaveEventTarget->GetPrimaryFrame(FlushType::Layout);
9147:         if (MOZ_UNLIKELY(mPresShell->IsDestroying())) {
9148:           return NS_OK;
9149:         }
9150:         if (frame) {
9151:           mPresShell->mCurrentEventTarget.mFrame = frame;
9152:           mPresShell->mCurrentEventTarget.mContent = deepestLeaveEventTarget;
9153:         }
9154:       }
9155:     }
9156:   }
9157: 
9158:   // 2. Give event to the DOM for third party and JS use.
9159:   bool wasHandlingKeyBoardEvent = nsContentUtils::IsHandlingKeyBoardEvent();
9160:   if (aEvent->mClass == eKeyboardEventClass) {
9161:     nsContentUtils::SetIsHandlingKeyBoardEvent(true);
9162:   }
9163:   // If EventStateManager or something wants reply from remote process and
9164:   // needs to win any other event listeners in chrome, the event is both
9165:   // stopped its propagation and marked as "waiting reply from remote
9166:   // process".  In this case, PresShell shouldn't dispatch the event into
9167:   // the DOM tree because they don't have a chance to stop propagation in
9168:   // the system event group.  On the other hand, if its propagation is not
9169:   // stopped, that means that the event may be reserved by chrome.  If it's
9170:   // reserved by chrome, the event shouldn't be sent to any remote
9171:   // processes.  In this case, PresShell needs to dispatch the event to
9172:   // the DOM tree for checking if it's reserved.
9173:   if (aEvent->IsAllowedToDispatchDOMEvent() &&
9174:       !(aEvent->PropagationStopped() &&
9175:         aEvent->IsWaitingReplyFromRemoteProcess())) {
9176:     MOZ_ASSERT(nsContentUtils::IsSafeToRunScript(),
9177:                "Somebody changed aEvent to cause a DOM event!");
9178:     nsPresShellEventCB eventCB(mPresShell);
9179:     if (nsIFrame* target = mPresShell->GetCurrentEventFrame()) {
9180:       if (target->OnlySystemGroupDispatch(aEvent->mMessage)) {
9181:         aEvent->StopPropagation();
9182:       }
9183:     }
9184:     if (aEvent->mClass == eTouchEventClass) {
9185:       DispatchTouchEventToDOM(aEvent, aEventStatus, &eventCB, aTouchIsNew);
9186:     } else {
9187:       DispatchEventToDOM(aEvent, aEventStatus, &eventCB);
9188:     }
9189:   }
9190: 
9191:   nsContentUtils::SetIsHandlingKeyBoardEvent(wasHandlingKeyBoardEvent);
9192: 
9193:   if (mPresShell->IsDestroying()) {
9194:     return NS_OK;
9195:   }
9196: 
9197:   // 3. Give event to event manager for post event state changes and
9198:   //    generation of synthetic events.
9199:   // Refetch the prescontext, in case it changed.
9200:   RefPtr<nsPresContext> presContext = GetPresContext();
9201:   return aEventStateManager->PostHandleEvent(
9202:       presContext, aEvent, mPresShell->GetCurrentEventFrame(), aEventStatus,
9203:       aOverrideClickTarget);
9204: }
